import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios"; // <-- use your api instance

const AddAppointment = () => {
  const navigate = useNavigate();
const [appointment, setAppointment] = useState({
  lead: "",
  vehicle: "",
  appointmentType: "viewing",
  date: "",
  time: "",
  notes: "",
  status: "scheduled",
});
  const [leads, setLeads] = useState([]);
  const [vehicles, setVehicles] = useState([]);

  useEffect(() => {
    // Fetch leads
    const fetchLeads = async () => {
      const res = await axios.get("http://localhost:8070/api/leads");
      setLeads(res.data);
    };
    // Fetch vehicles
    const fetchVehicles = async () => {
      const res = await axios.get("http://localhost:8070/api/vehicles");
      setVehicles(res.data.filter(v => v.status === "available"));
    };
    fetchLeads();
    fetchVehicles();
  }, []);

  const handleChange = (e) => {
    setAppointment({ ...appointment, [e.target.name]: e.target.value });
  };

const handleSubmit = async (e) => {
  e.preventDefault();
  try {
    await api.post("/appointments/add", appointment);
    alert("Appointment added!");
    navigate("/appointments");
  } catch (err) {
    alert(err.response?.data?.message || "Error adding appointment");
  }
};

  return (
    <div style={{ padding: 20 }}>
      <h2>Add Appointment</h2>
      <form onSubmit={handleSubmit}>
        <label>
          Lead:
          <select name="lead" value={appointment.lead} onChange={handleChange} required>
            <option value="">Select Lead</option>
            {leads.map((l) => <option key={l._id} value={l._id}>{l.name}</option>)}
          </select>
        </label>
        <br /><br />
        <label>
          Vehicle:
          <select name="vehicle" value={appointment.vehicle} onChange={handleChange} required>
            <option value="">Select Vehicle</option>
            {vehicles.map((v) => <option key={v._id} value={v._id}>{v.brand} {v.model}</option>)}
          </select>
        </label>
        <br /><br />
        <label>
          Date: <input type="date" name="date" value={appointment.date} onChange={handleChange} required />
        </label>
        <br /><br />
        <label>
          Time: <input type="time" name="time" value={appointment.time} onChange={handleChange} required />
        </label>
        <br /><br />
        <label>
          Status:
          <select name="status" value={appointment.status} onChange={handleChange}>
            <option value="scheduled">Scheduled</option>
            <option value="completed">Completed</option>
            <option value="cancelled">Cancelled</option>
          </select>
        </label>
        <label>
         Type:
          <select name="appointmentType" value={appointment.appointmentType} onChange={handleChange}>
            <option value="viewing">Viewing</option>
          <option value="test_drive">Test Drive</option>
          <option value="follow_up">Follow Up</option>
         </select>
        </label>

<br /><br />

<label>
  Notes:
  <textarea
    name="notes"
    value={appointment.notes}
    onChange={handleChange}
    placeholder="Interaction notes"
    rows={3}
  />
</label>
        <br /><br />
        <button type="submit">Save Appointment</button>
      </form>
    </div>
  );
};

export default AddAppointment;
